diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..3f366cc63a12 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8268,6 +8268,7 @@ static std::optional<bool> isImpliedCondCommonOperandWithConstants(
 /// Return true if LHS implies RHS (expanded to its components as "R0 RPred R1")
 /// is true.  Return false if LHS implies RHS is false. Otherwise, return
 /// std::nullopt if we can't infer anything.
+
 static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
                                               CmpInst::Predicate RPred,
                                               const Value *R0, const Value *R1,
@@ -8286,6 +8287,49 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   if (areMatchingOperands(L0, L1, R0, R1, AreSwappedOps))
     return isImpliedCondMatchingOperands(LPred, RPred, AreSwappedOps);

+  // Recognize equivalent unsigned overflow/non-overflow tests of the same add:
+  //   (add X, Y) u<  X  <=>  (add X, Y) u<  Y
+  //   (add X, Y) u>= X  <=>  (add X, Y) u>= Y
+  //
+  // These are the canonical carry/no-carry tests for unsigned addition.
+  auto matchAddBound = [](CmpInst::Predicate Pred, const Value *Op0,
+                          const Value *Op1, const Value *&Add,
+                          const Value *&Bound, const Value *&OtherBound)
+      -> bool {
+    if (Pred != CmpInst::ICMP_ULT && Pred != CmpInst::ICMP_UGE)
+      return false;
+
+    const Value *X, *Y;
+    if (!match(Op0, m_Add(m_Value(X), m_Value(Y))))
+      return false;
+
+    if (Op1 == X) {
+      Add = Op0;
+      Bound = X;
+      OtherBound = Y;
+      return true;
+    }
+    if (Op1 == Y) {
+      Add = Op0;
+      Bound = Y;
+      OtherBound = X;
+      return true;
+    }
+    return false;
+  };
+
+  {
+    const Value *LAdd, *LBound, *LOtherBound;
+    const Value *RAdd, *RBound, *ROtherBound;
+    if (LPred == RPred &&
+        matchAddBound(LPred, L0, L1, LAdd, LBound, LOtherBound) &&
+        matchAddBound(RPred, R0, R1, RAdd, RBound, ROtherBound) &&
+        LAdd == RAdd &&
+        LBound == ROtherBound &&
+        LOtherBound == RBound)
+      return true;
+  }
+
   // Can we infer anything when the 0-operands match and the 1-operands are
   // constants (not necessarily matching)?
   const APInt *LC, *RC;
@@ -8298,6 +8342,7 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   return std::nullopt;
 }

+
 /// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
 /// false.  Otherwise, return std::nullopt if we can't infer anything.  We
 /// expect the RHS to be an icmp and the LHS to be an 'and', 'or', or a 'select'
